mapper.select:
select
county.*
distinct city.*
from sys_administrative_division_code city left join sys_administrative_division_code county on city.code = county.pcode left join sys_administrative_division_code province on city.pcode = province.code where province.name = #{province} and (city.name = #{city} or city.name = '市辖区')
and county.name = #{county}

select c.code
from sys_administrative_division_code c
left join sys_administrative_division_code p on c.pcode = p.code
left join sys_administrative_division_code pp on p.pcode = pp.code
left join sys_administrative_division_code ppp on pp.pcode = ppp.code
where c.code = #{code}
or p.code = #{code}
or pp.code = #{code}
or ppp.code = #{code}
